select position_id from coin_api_position cap

    api_id = #{apiId} and position_id in

        #{id}

SELECT
ROUND(
AVG(daily_profit) / NULLIF(STDDEV_POP(daily_profit), 0),
4
) AS sharpeRatio
FROM (
SELECT
DATE(FROM_UNIXTIME(ctime / 1000)) AS day,
SUM(CAST(net_profit AS DECIMAL(20,8))) AS daily_profit
FROM coin_api_position
WHERE api_id = #{apiId}
AND ctime >= #{time}
AND close IS NOT NULL
GROUP BY DATE(FROM_UNIXTIME(ctime / 1000))
) t;
